209	// Walks target.xml and every <xi:include> annex, returning the merged
210	// register-name -> packet-number map.
211	inline auto discover_reg_map(gdbstub::Session& sess) -> gdbstub::RegMap
212	{
213	  gdbstub::RegMap map;
214	  const auto target_xml = fetch_feature_xml(sess, "target.xml");
215	  unsigned next = 0;
216	  for (const auto& annex : gdbstub::parse_target_xml(target_xml)) {
217	    const auto annex_xml = fetch_feature_xml(sess, annex);
218	    gdbstub::parse_feature_xml(annex_xml, map, next);
219	  }
220	  return map;
221	}
